	    				szMsg = "To위치Guide(" + szYdToLocGuide + ")로 조회중 parameter error 발생! <getYdLocsrchrng,5>";
	    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
	    				nReturn = 440;
	    				return nReturn;
