					rsStock = JDTORecordFactory.getInstance().createRecordSet("");
					
					szMsg = "스케줄To위치점검(" + szMethodName + ")의 Query시작 <getYdStock,130>";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					
					intRtnVal = ydStockDao.getYdStock(recPara, rsStock, 130);
					
					if(intRtnVal<=0){
		    			if(intRtnVal == 0) {
		    				szMsg = "예약번호(" + szWbookId + ")에 대한 재료데이터가 없습니다.<getYdStock,130>";
		    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
		    				nReturn = 410;
		    				return nReturn;
		    			}else if(intRtnVal == -2) {
		    				szMsg = "예약번호(" + szWbookId + ")로 조회중 parameter error 발생!<getYdStock,130>";
		    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
		    				nReturn = 420;
		    				return nReturn;
		    			}
		    		}
					
					rsStock.absolute(1);
					recStock = rsStock.getRecord();
								
					szRouteGp  = ydDaoUtils.paraRecChkNull(recStock,"YD_ROUTE_GP");
								
					szMsg = "스케줄To위치점검(" + szMethodName + ")의 Query완료 <getYdStock,130>";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					// End
					/********************************************************************************/
					
					/********************************************************************************/
					// 예약번호로 예약재료의 전체 매수와 합계중량을 읽어오는 모듈
					JDTORecord recSumPara = JDTORecordFactory.getInstance().create();
					
					recSumPara.setField("YD_WBOOK_ID", szWbookId);
					rsWbookMtl = JDTORecordFactory.getInstance().createRecordSet("");
					
					szMsg = "스케줄To위치점검(" + szMethodName + ")의 Query시작 <getYdWrkbookmtl,27>";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					
					intRtnVal = ydWrkbookMtlDao.getYdWrkbookmtl(recSumPara, rsWbookMtl, 27);
					
					if(intRtnVal<=0){
		    			if(intRtnVal == 0) {
		    				szMsg = "예약번호(" + szWbookId + ")에 대한 재료데이터가 없습니다.<getYdWrkbookmtl,27>";
		    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
		    				nReturn = 410;
		    				return nReturn;
		    			}else if(intRtnVal == -2) {
		    				szMsg = "예약번호(" + szWbookId + ")로 조회중 parameter error 발생!<getYdWrkbookmtl,27>";
		    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
		    				nReturn = 420;
		    				return nReturn;
		    			}
		    		}
					
					rsWbookMtl.absolute(1);
					recWbookMtl = rsWbookMtl.getRecord();
								
					lngStlCnt  	= ydDaoUtils.paraRecChkNullLong(recWbookMtl,"STL_CNT"); 
					lngStlWt  	= ydDaoUtils.paraRecChkNullLong(recWbookMtl,"STL_WT");
					
					szMsg = "스케줄To위치점검(" + szMethodName + ")의 Query완료 <getYdWrkbookmtl,27>";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					
					// End
					/********************************************************************************/
					
					// *************************************************** //
					// 스케줄코드, 목표행선구분, 재료매수, 합계중량으로
					// 적재가능한 BED 존재유무를 체크하는 루틴을 작성해야함
					// *************************************************** //
					
					JDTORecord recBedPara = JDTORecordFactory.getInstance().create();
					
