					recBedPara.setField("YD_ROUTE_GP1", szRouteGp);
					recBedPara.setField("YD_SCH_CD2", szSchCd);
					recBedPara.setField("YD_ROUTE_GP2", szRouteGp);
					recBedPara.setField("YD_SCH_CD3", szSchCd);
					recBedPara.setField("YD_ROUTE_GP3", szRouteGp);
					
