		    			intCntStlNo       = ydDaoUtils.paraRecChkNullInt(recBed, "CNT_STL_NO");
		    			lngSumMtlWt       = ydDaoUtils.paraRecChkNullLong(recBed, "SUM_MTL_WT");
		    			
