						recTemp2.setField("YD_MTL_L", 		ydDaoUtils.paraRecChkNull(recTemp, "YD_MTL_L"));
						recTemp2.setField("YD_MTL_WT", 		ydDaoUtils.paraRecChkNull(recTemp, "YD_MTL_WT"));
						recTemp2.setField("YD_AIM_RT_GP", 	ydDaoUtils.paraRecChkNull(recTemp, "YD_AIM_RT_GP"));
