        String szStkBedNo          = ""; 
        String szYD_STK_LYR_NO		= "";
        
        //등급
        int intGrade               = 1001;
        //이전등급중 가장 좋은 등급
        int intGradeSave           = 1000;
        //등급의 적치단정보
        String szGradeColGp          = "";
        String szGradeBedNo          = "";
        String szGradeLyrNo          = "";
        
        String szQuery     = "";
