        	szSTL_NO				= ydDaoUtils.paraRecChkNull(recGetCrnWrkMtl, "STL_NO");
        	szYD_UP_WO_LOC			= ydDaoUtils.paraRecChkNull(recGetCrnWrkMtl, "YD_UP_WO_LOC");
        	
