        		//	수정일 : 2010.03.08 - 임춘수
        		//-------------------------------------------------------------------------------------
        		
        		//TO위치평점판단 모듈 호출 시 공베드인 경우에는 NULL로 판단을 하기 위해서 설정
        		recStkHighestLyr			= null;
        		
        		szMsg="적치열[" + szStkColGp + "] 베드[" + szStkBedNo + "]의 적치단 정보 조회 시작";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
        		
        		rsResult				= JDTORecordFactory.getInstance().createRecordSet("");
				recInTemp 				= JDTORecordFactory.getInstance().create();
	        	recInTemp.setField("YD_STK_COL_GP", 			szStkColGp);
	        	recInTemp.setField("YD_STK_BED_NO", 			szStkBedNo);
	        	
	        	String szRtnMsg			= DaoManager.getYdStklyr(recInTemp, rsResult, 6);
	        	
	        	if( szRtnMsg.equals(YdConstant.RETN_CD_SUCCESS) ) {
	        		rsResult.first();
					
					recInTemp			= rsResult.getRecord();
					
					szYD_STK_LYR_MTL_STAT	= ydDaoUtils.paraRecChkNull(recInTemp, "YD_STK_LYR_MTL_STAT");
					intSH_CNT				= ydDaoUtils.paraRecChkNullInt(recInTemp, "SH_CNT");
					
					szYD_STK_LYR_NO			= ydDaoUtils.paraRecChkNull(recInTemp, "YD_STK_LYR_NO");;
					
					if(szYD_STK_LYR_MTL_STAT.equals(YdConstant.YD_STK_LYR_MTL_STAT_UN_WAIT)) {
						szMsg="적치열[" + szStkColGp + "] 베드[" + szStkBedNo + "]에 권상대기인 재료가 존재하므로 베드를 제외시킴";
	    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
	    				continue;
					}
					
					recStkHighestLyr			= JDTORecordFactory.getInstance().create();
					
					recStkHighestLyr.setRecord(recInTemp);
					
					szMsg="적치열[" + szStkColGp + "] 베드[" + szStkBedNo + "]가 공베드가 아님 - 재료 매수["+intSH_CNT+"], 재료가 존재하는 최상단["+szYD_STK_LYR_NO+"]";
    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
    				
	        	}else if( szRtnMsg.equals(YdConstant.RETN_CD_NOTEXIST) ) {
	        		
					szMsg="적치열[" + szStkColGp + "] 베드[" + szStkBedNo + "]가 공베드이므로 베드사용가능.";
    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
    				
    				bIsEmptyBed				= true;
    				
				}else{
					
					szMsg="적치열[" + szStkColGp + "] 베드[" + szStkBedNo + "]의 적치단 정보 조회 시 오류발생 - 메세지 : " + szRtnMsg;
    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
    				
					continue;
				}
        		
        		//-------------------------------------------------------------------------------------
        		
	        	//-------------------------------------------------------------------------------------
