    /**
     * 오퍼레이션명 : 크레인스케줄 Update
     *  
     * @param  ● msgRecord, intGp
     * @return ● intRtnVal '1'이상: 성공   '0'이하: 실패
     * @throws ● JDTOException
     */
    public int Y1UpdYdCrnsch(JDTORecord msgRecord, int intGp) throws JDTOException {
    	YdCrnSchDao ydCrnschDao = new YdCrnSchDao();

    	int intRtnVal = 0 ;
    	
    	String szMsg        = "";
    	String szMethodName = "Y1UpdYdCrnsch";
    	String szOperationName  = "C연주크레인스케줄 Update";
		try{
			
			intRtnVal = ydCrnschDao.updYdCrnsch(msgRecord, intGp);		        
			if(intRtnVal <= 0) {
    			if(intRtnVal == 0) {
    				szMsg="<Y1UpdYdCrnsch> updYdCrnsch data not found";
    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.INFO);
    			}else if(intRtnVal == -1) {
    				szMsg="<Y1UpdYdCrnsch> updYdCrnsch duplicate data";
    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);	
    			}else if(intRtnVal == -2) {
    				szMsg="<Y1UpdYdCrnsch> updYdCrnsch parameter error";
    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
    			}else if(intRtnVal == -3){
    				szMsg="<Y1UpdYdCrnsch> updYdCrnsch execution failed";
    				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
    			}
    			return intRtnVal = -1;
    		}
			return intRtnVal ;
		}catch(Exception e){
			szMsg="["+szOperationName+"] Exception발생 : " + e.getMessage();
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
			throw new JDTOException(szMsg);
        }//end of try~catch
		
    }// end of Y1UpdYdCrnsch
    
