	    	szTRN_EQP_CD    = ydDaoUtils.paraRecChkNull(recOutTemp, "TRN_EQP_CD");
	    	szYD_CAR_USE_GP = ydDaoUtils.paraRecChkNull(recOutTemp, "YD_CAR_USE_GP");
