		int intStkLyrMax           = 0;
		long lngStkLyrWtMax 	   = 0;
		double lngStkLyrHMax         = 0;
		
		//크레인작업재료의 최하단 산적LotType,산적Lot코드,폭
		String szCrnWrkMtlStkLotTp = "";
		String szCrnWrkMtlStkLotCd = "";
		long lngCrnWrkMtlW		   = 0;
		
