	/**
	 *      [A] 오퍼레이션명 : 전문전송버퍼
	 *  
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param msgRecord
	 * @return
	 * @throws JDTOException
	 */
	public void procForwardTcRecord(JDTORecord msgRecord)throws JDTOException  {
		String szMsg			=	"";
		String szMethodName		=	"procForwardTcRecord";
		String szOperationName	=	"전문전송버퍼";
		
		JDTORecord recPara 		= null;
		
		String szFieldName		= null;
		String szFieldValue		= null;
		
		String szIF_ID			= "";
		
		recPara	= JDTORecordFactory.getInstance().create();
		
		Iterator iter = msgRecord.iterateName();
		
		while( iter.hasNext() ) {
			szFieldName = (String)iter.next();
			if( szFieldName.equals(YdConstant.JMS_TC_CD) ||
					szFieldName.equals(YdConstant.MSG_ID) ||
					szFieldName.equals(YdConstant.TC_CODE)
			) {
				continue;
			}
			
			szFieldValue = msgRecord.getFieldString(szFieldName);
			
			if( szFieldName.equals(YdConstant.BUFFER_TC_CD)) {
				recPara.setField(YdConstant.JMS_TC_CD, szFieldValue);
				recPara.setField(YdConstant.BUFFER_TC_CD, szFieldValue);
				
				szIF_ID = szFieldValue;
			}else{
				recPara.setField(szFieldName, szFieldValue);
			}
		}
		// 전사물류개선 2021. 1. 7
		if(!("YDY8L004".equals(szIF_ID)||"YDY9L004".equals(szIF_ID)) ){//작업지시인 경우 SLEEP을 안함 - 취소/삭제시 문제발생
			
			String sHmiStat 		= "N";
			int iTime 				= 0;
			
			String sQuery1			= "ym.facilitystatus.facilityinquiry.dao.YdEquipDAO.SelectWBHMISTAT";
			JDTORecord wbJr 		= (new com.inisteel.cim.ym.facilitystatus.facilityinquiry.dao.CraneSchDAO()).getData(sQuery1, new Object[]{ "2XRT06" });
			if (wbJr != null){ 
				sHmiStat	= StringHelper.evl(wbJr.getFieldString("HMI_STAT"), "");
				iTime		= Integer.parseInt(StringHelper.evl(wbJr.getFieldString("DOWN_CD"), "0"));
			}
			
			szMsg="■■■■■■■■■■ SLEEP TIME 기준 : sHmiStat="+sHmiStat +"/iTime="+iTime;
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
			
			szMsg="■■■■■■■■■■ SLEEP TIME 기준 : START ="+YdUtils.getCurDate("yyyyMMddHHmmss");;
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
			
			if("Y".equals(sHmiStat)){
				
				try{
					Thread.sleep(iTime);		//시간 대기.(1초(1000) 여유)
				}catch(Exception e){
					e.printStackTrace();
				}
			}
			
			szMsg="■■■■■■■■■■ SLEEP TIME 기준 : END ="+YdUtils.getCurDate("yyyyMMddHHmmss");;
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		}
				
		ydDelegate.sendMsg(recPara);
			
	}// end of procForwardTcRecord()
